#include <vector>
#include <queue>
#include <unordered_map>
#include <set>
#include <algorithm>

using namespace std;

long long solve(vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;

    const int max_num = 1000000;
    vector<int> spf(max_num + 1, 0);

    for (int i = 2; i <= max_num; ++i) {
        if (spf[i] == 0) {
            spf[i] = i;
            for (int j = i * 2; j <= max_num; j += i) {
                if (spf[j] == 0) {
                    spf[j] = i;
                }
            }
        }
    }

    unordered_map<long long, vector<int>> prime_to_indices;

    for (int j = 0; j < n; ++j) {
        long long x = nums[j];
        if (x == 1) continue;

        set<long long> factors;
        long long temp = x;
        while (temp > 1) {
            long long p = spf[temp];
            factors.insert(p);
            while (temp % p == 0) {
                temp /= p;
            }
        }

        for (long long p : factors) {
            prime_to_indices[p].push_back(j);
        }
    }

    vector<int> dist(n, -1);
    queue<int> q;
    q.push(0);
    dist[0] = 0;

    while (!q.empty()) {
        int i = q.front();
        q.pop();

        if (i == n - 1) return dist[i];

        // Check adjacent indices
        for (int di : {-1, 1}) {
            int j = i + di;
            if (j >= 0 && j < n && dist[j] == -1) {
                dist[j] = dist[i] + 1;
                q.push(j);
            }
        }

        // Check if current number is a prime
        long long x = nums[i];
        if (x == 1) continue;

        set<long long> factors;
        long long temp = x;
        while (temp > 1) {
            long long p = spf[temp];
            factors.insert(p);
            while (temp % p == 0) {
                temp /= p;
            }
        }

        if (factors.size() == 1 && *factors.begin() == x) {
            long long p = x;
            for (int j : prime_to_indices[p]) {
                if (j != i && dist[j] == -1) {
                    dist[j] = dist[i] + 1;
                    q.push(j);
                }
            }
        }
    }

    return -1;
}

