function solve(nums: number[]): number {
    const max_num = 1000000;
    const spf = new Array(max_num + 1).fill(0);
    for (let i = 2; i <= max_num; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * 2; j <= max_num; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    const prime_to_indices = new Map<number, number[]>();
    for (let i = 0; i < nums.length; i++) {
        const x = nums[i];
        if (x === 1) continue;
        const factors = new Set<number>();
        let temp = x;
        while (temp > 1) {
            const p = spf[temp];
            factors.add(p);
            while (temp % p === 0) {
                temp /= p;
            }
        }
        for (const p of factors) {
            if (!prime_to_indices.has(p)) {
                prime_to_indices.set(p, []);
            }
            prime_to_indices.get(p).push(i);
        }
    }

    const n = nums.length;
    const dist = new Array(n).fill(-1);
    const q: number[] = [0];
    dist[0] = 0;

    while (q.length > 0) {
        const i = q.shift()!;
        if (i === n - 1) return dist[i];
        // Check adjacent indices
        for (const di of [-1, 1]) {
            const j = i + di;
            if (j >= 0 && j < n && dist[j] === -1) {
                dist[j] = dist[i] + 1;
                q.push(j);
            }
        }
        // Check if current number is a prime
        const x = nums[i];
        if (x === 1) continue;
        const factors = new Set<number>();
        let temp = x;
        while (temp > 1) {
            const p = spf[temp];
            factors.add(p);
            while (temp % p === 0) {
                temp /= p;
            }
        }
        if (factors.size === 1 && factors.has(x)) {
            const p = x;
            const indices = prime_to_indices.get(p);
            if (indices) {
                for (const j of indices) {
                    if (j !== i && dist[j] === -1) {
                        dist[j] = dist[i] + 1;
                        q.push(j);
                    }
                }
            }
        }
    }

    return -1;
}
