        if (x == 1) continue;

        set<long long> factors;
        long long temp = x;
        while (temp > 1) {
            long long p = spf[temp];
            factors.insert(p);
            while (temp % p == 0) {
                temp /= p;
            }
        }

        if (factors.size() == 1 && *factors.begin() == x) {
